const htmlOutput = $('Generate HTML Article').first().json.output || '';

// Step 1: Strip markdown code fences if present
let cleanHtml = htmlOutput
  .replace(/^```html\s*\n?/gm, '')
  .replace(/^```\s*$/gm, '')
  .trim();

// Step 2: Fix wpautop-unsafe patterns (SVG + text on separate lines)
cleanHtml = cleanHtml.replace(/<\/svg>\s*\n\s*/g, '</svg> ');
cleanHtml = cleanHtml.replace(/(<a[^>]*>)\s*\n\s*(<svg)/g, '$1$2');
cleanHtml = cleanHtml.replace(/<\/svg>\s*\n\s*([^<])/g, '</svg> $1');

// Step 3: Validate mandatory sections
const hasArticleOpen = /<article[\s>]/.test(cleanHtml);
const hasArticleClose = cleanHtml.includes('</article>');
const hasToc = cleanHtml.includes('\u05ea\u05d5\u05db\u05df \u05d4\u05e2\u05e0\u05d9\u05d9\u05e0\u05d9\u05dd');
const hasFaq = /\u05e9\u05d0\u05dc\u05d5\u05ea\s*\u05e0\u05e4\u05d5\u05e6\u05d5\u05ea/.test(cleanHtml) || cleanHtml.includes('faq');
const hasAuthor = cleanHtml.includes('\u05d4\u05de\u05db\u05dc\u05dc\u05d4 \u05d4\u05d0\u05e7\u05d3\u05de\u05d9\u05ea \u05e0\u05ea\u05e0\u05d9\u05d4');
const hasSchema = cleanHtml.includes('application/ld+json');
const hasFloatingContact = /floating.?contact/i.test(cleanHtml) || cleanHtml.includes('\u05d9\u05d9\u05e2\u05d5\u05e5 \u05d5\u05d4\u05e8\u05e9\u05de\u05d4');
const hasBackToTop = /back.?to.?top/i.test(cleanHtml) || cleanHtml.includes('scrollTo');

// Date freshness: no stale years in "updated" labels
const stalePattern = /\u05e2\u05d5\u05d3\u05db\u05df \u05d0\u05d7\u05e8\u05d5\u05e0\u05d4:\s*(20[0-1][0-9]|202[0-5])/g;
const hasNoStaleYear = !stalePattern.test(cleanHtml);

const validation = {
  article_wrapper: hasArticleOpen && hasArticleClose,
  toc_present: hasToc,
  faq_present: hasFaq,
  author_section: hasAuthor,
  json_ld_schemas: hasSchema,
  floating_contact: hasFloatingContact,
  back_to_top: hasBackToTop,
  date_freshness: hasNoStaleYear,
  all_passed: (hasArticleOpen && hasArticleClose && hasToc && hasFaq && hasAuthor && hasSchema && hasFloatingContact && hasBackToTop && hasNoStaleYear)
};

// Count words (strip HTML tags first)
const textOnly = cleanHtml.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
const wordCount = textOnly.split(/\s+/).length;

return [{
  json: {
    html: cleanHtml,
    validation: validation,
    word_count: wordCount,
    char_count: cleanHtml.length
  }
}];

const validation = $('Validate & Clean HTML').first().json.validation;
const wordCount = $('Validate & Clean HTML').first().json.word_count;
const charCount = $('Validate & Clean HTML').first().json.char_count;

const failures = Object.entries(validation)
  .filter(([key, val]) => key !== 'all_passed' && val === false)
  .map(([key]) => key.replace(/_/g, ' '));

const checkLabels = {
  'article wrapper': 'Missing <article> wrapper element',
  'toc present': 'Missing Table of Contents section',
  'faq present': 'Missing FAQ section',
  'author section': 'Missing About the Brand / Author section',
  'json ld schemas': 'Missing JSON-LD structured data schemas',
  'floating contact': 'Missing floating contact button',
  'back to top': 'Missing back-to-top button',
  'date freshness': 'Stale dates found (pre-2026 years in "last updated" labels)'
};

const failureDetails = failures.map(f => ({
  check: f,
  description: checkLabels[f] || 'Check failed'
}));

return [{
  json: {
    status: 'VALIDATION_FAILED',
    failed_checks: failures,
    failure_details: failureDetails,
    total_checks: Object.keys(validation).length - 1,
    passed_checks: Object.keys(validation).length - 1 - failures.length,
    word_count: wordCount,
    char_count: charCount,
    message: `HTML validation failed. ${failures.length} check(s) did not pass: ${failures.join(', ')}. Please review and regenerate the article.`
  }
}];
